function calculateROI({ initialInvestment, annualProductionVolume, avgSellingPrice, annualOperatingCosts, projectLifespan, discountRate, geopoliticalRiskImpact, supplyChainPremium, taxRate }) {
    // Input validation and normalization
    initialInvestment = Math.max(0, parseFloat(initialInvestment));
    annualProductionVolume = Math.max(0, parseFloat(annualProductionVolume));
    avgSellingPrice = Math.max(0, parseFloat(avgSellingPrice));
    annualOperatingCosts = Math.max(0, parseFloat(annualOperatingCosts));
    projectLifespan = Math.max(1, parseInt(projectLifespan));
    discountRate = Math.max(0, Math.min(100, parseFloat(discountRate))) / 100;
    geopoliticalRiskImpact = Math.max(0, Math.min(100, parseFloat(geopoliticalRiskImpact))) / 100;
    supplyChainPremium = Math.max(0, Math.min(100, parseFloat(supplyChainPremium))) / 100;
    taxRate = Math.max(0, Math.min(100, parseFloat(taxRate))) / 100;

    if (initialInvestment === 0) {
        return {
            totalProjectRevenue: 0,
            totalProjectOperatingCosts: 0,
            totalProjectTax: 0,
            totalProjectNetProfit: 0,
            roi: 0,
            npv: 0,
            paybackPeriod: 0
        };
    }

    let annualCashFlows = [];
    let totalProjectRevenue = 0;
    let totalProjectOperatingCosts = 0;
    let totalProjectTax = 0;

    for (let year = 1; year <= projectLifespan; year++) {
        const annualGrossRevenue = annualProductionVolume * avgSellingPrice;
        const adjustedAnnualRevenue = annualGrossRevenue * (1 - geopoliticalRiskImpact) * (1 + supplyChainPremium);

        const annualOperatingProfitBeforeTax = adjustedAnnualRevenue - annualOperatingCosts;
        const annualTax = Math.max(0, annualOperatingProfitBeforeTax) * taxRate;
        const annualNetCashFlow = annualOperatingProfitBeforeTax - annualTax;

        annualCashFlows.push(annualNetCashFlow);
        totalProjectRevenue += adjustedAnnualRevenue;
        totalProjectOperatingCosts += annualOperatingCosts;
        totalProjectTax += annualTax;
    }

    // Calculate NPV
    let npv = -initialInvestment; // Year 0 investment
    for (let i = 0; i < annualCashFlows.length; i++) {
        npv += annualCashFlows[i] / Math.pow(1 + discountRate, i + 1);
    }

    // Calculate Total Project Net Profit (sum of all cash flows over life minus initial investment)
    const totalProjectNetProfit = annualCashFlows.reduce((sum, cf) => sum + cf, 0) - initialInvestment;

    // Calculate ROI
    const roi = (initialInvestment !== 0) ? (totalProjectNetProfit / initialInvestment) * 100 : 0;

    // Calculate Payback Period
    let cumulativeCashFlowForPayback = -initialInvestment;
    let paybackPeriod = Infinity;
    for (let i = 0; i < annualCashFlows.length; i++) {
        const currentYearCashFlow = annualCashFlows[i];
        if (paybackPeriod === Infinity) { // Only calculate if not yet paid back
            if (cumulativeCashFlowForPayback + currentYearCashFlow >= 0) {
                // Paid back in this year
                const yearsPassed = i; // Years *before* this current year
                const amountNeededThisYear = -cumulativeCashFlowForPayback; // Amount still needed to break even
                if (currentYearCashFlow > 0) {
                    paybackPeriod = yearsPassed + (amountNeededThisYear / currentYearCashFlow);
                } else if (currentYearCashFlow === 0 && amountNeededThisYear <= 0) {
                    // If currentYearCashFlow is zero, but cumulative was already non-negative, then it's paid back at `yearsPassed`
                    paybackPeriod = yearsPassed;
                } // Otherwise, if currentYearCashFlow <= 0 and amountNeededThisYear > 0, cannot pay back
            }
        }
        cumulativeCashFlowForPayback += currentYearCashFlow;
    }
    // If total project net profit is negative or not paid back, payback period is Infinity.
    if (totalProjectNetProfit < 0 || paybackPeriod > projectLifespan) {
        paybackPeriod = Infinity;
    }

    return {
        totalProjectRevenue: totalProjectRevenue,
        totalProjectOperatingCosts: totalProjectOperatingCosts,
        totalProjectTax: totalProjectTax,
        totalProjectNetProfit: totalProjectNetProfit,
        roi: roi,
        npv: npv,
        paybackPeriod: paybackPeriod
    };
}
